(function($){var container,button,menu,links,subMenus;container=document.getElementById('site-navigation');if(!container){return}
button=container.getElementsByTagName('button')[0];if('undefined'===typeof button){return}
menu=container.getElementsByTagName('ul')[0];if('undefined'===typeof menu){button.style.display='none';return}
menu.setAttribute('aria-expanded','false');if(-1===menu.className.indexOf('nav-menu')){menu.className+=' nav-menu'}
button.onclick=function(){if(-1!==container.className.indexOf('toggled')){container.className=container.className.replace(' toggled','');button.setAttribute('aria-expanded','false');menu.setAttribute('aria-expanded','false')}else{container.className+=' toggled';button.setAttribute('aria-expanded','true');menu.setAttribute('aria-expanded','true')}};links=menu.getElementsByTagName('a');subMenus=menu.getElementsByTagName('ul');for(var i=0,len=subMenus.length;i<len;i++){subMenus[i].parentNode.setAttribute('aria-haspopup','true')}
for(i=0,len=links.length;i<len;i++){links[i].addEventListener('focus',toggleFocus,!0);links[i].addEventListener('blur',toggleFocus,!0)}
function toggleFocus(){var self=this;while(-1===self.className.indexOf('nav-menu')){if('li'===self.tagName.toLowerCase()){if(-1!==self.className.indexOf('focus')){self.className=self.className.replace(' focus','')}else{self.className+=' focus'}}
self=self.parentElement}}
function autoHeightAnimate(element,time){var curHeight=element.height(),autoHeight=element.css('height','auto').height();element.height(curHeight);element.stop().animate({height:autoHeight},parseInt(time))}
var _window;_window={is_mobile:!1,is_tablet:!1,width:$(window).outerWidth(),height:$(window).outerHeight(),is_portable:function(){if(this.width<=1280&&this.width>768){this.is_tablet=!0;this.is_mobile=!1}else if(this.width>=1280){this.is_tablet=!1;this.is_mobile=!1}else if(this.width<768){this.is_tablet=!1;this.is_mobile=!0}}};$(window).on('resize load',function(){_window.width=$(window).outerWidth();_window.height=$(window).outerHeight();_window.is_portable();if(_window.is_tablet||_window.is_mobile){$(".site-header .nav-menu li.menu-item-has-children").each(function(){if($(this).find('.arrow-toggle').length>0)return;var $parent=this;var $arrow=$("<span class='arrow-toggle'><i class='fa fa-angle-down' aria-hidden='true'></i></span>");$(this).prepend($arrow);$arrow.on('click',function(){$($parent).toggleClass("expandeds");$($parent).find('> .sub-menu').slideToggle(500);$(".merge-navigation-wrapper").css('height',$(window).height())})})}})})(jQuery)